// src/lib/annotations/resources/Require.js

/**
 * @file Require.js
 * @description Annotation for registering external modules or resources
 * in the Dependency Injection (DI) container under a custom alias.
 */
class RequireAnnotation {
  /**
   * @param {Object} params
   * @param {string} params.alias - Alias für die DI-Registrierung
   * @param {string} params.module - Node.js Modulname oder Pfad
   */
  constructor(params) {
    this.alias = params.param1 || params.alias;
    this.module = params.param2 || params.module;
  }

  static get name() {
    return 'Require';
  }

  static get target() {
    return 'property';
  }

  static get args() {
    return true;
  }

  static get description() {
    return 'Registers external modules or resources under an alias for later injection via @Qualifier.';
  }
}

module.exports = RequireAnnotation;
